import React, { useState, useEffect } from 'react';
import { useNavigate, Navigate } from 'react-router-dom';
import { useAuth } from './hooks/useAuth';

/**
 * Home component for the expense tracker. This component handles
 * displaying the user's transactions, calculating totals and
 * providing a form to add new entries. All data is stored in
 * localStorage, so the app continues to work offline without
 * external dependencies. The design uses Tailwind CSS classes
 * to provide a modern and responsive user interface.
 */
export const Home = () => {
  const { userID, name, photo, isAuth } = useAuth();
  const navigate = useNavigate();

  // Load transactions from localStorage or initialize with an empty array
  const [transactions, setTransactions] = useState(() => {
    const stored = localStorage.getItem('transactions');
    if (stored) {
      try {
        return JSON.parse(stored);
      } catch (e) {
        console.error('Failed to parse transactions from localStorage', e);
      }
    }
    return [];
  });

  // Form fields for new entry
  const [newExp, setNewExp] = useState('');
  const [newPrice, setNewPrice] = useState('');
  const [newType, setNewType] = useState('Expense');
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Totals state: balance, income and expense
  const [total, setTotal] = useState({ balance: 0, income: 0, expense: 0 });

  // Recalculate totals whenever the transactions change
  useEffect(() => {
    let income = 0;
    let expense = 0;
    transactions.forEach((t) => {
      const amount = Number(t.price);
      if (t.type === 'Income') {
        income += amount;
      } else {
        expense += amount;
      }
    });
    setTotal({ balance: income - expense, income, expense });
  }, [transactions]);

  // Persist transactions to localStorage on every change
  useEffect(() => {
    localStorage.setItem('transactions', JSON.stringify(transactions));
  }, [transactions]);

  // Add a new transaction to the list
  const handleAdd = () => {
    if (!newExp.trim() || !newPrice) return;
    setIsSubmitting(true);
    setTimeout(() => {
      const newEntry = {
        id: Date.now().toString(),
        userID,
        exp: newExp.trim(),
        price: Number(newPrice),
        type: newType,
        createdAt: new Date().toISOString(),
      };
      setTransactions((prev) => [...prev, newEntry]);
      setNewExp('');
      setNewPrice('');
      setNewType('Expense');
      setIsSubmitting(false);
    }, 300);
  };

  // Delete a transaction by its id
  const handleDelete = (id) => {
    setTransactions((prev) => prev.filter((t) => t.id !== id));
  };

  // Sign the user out by clearing auth info and navigating to login
  const handleSignOut = () => {
    localStorage.removeItem('auth');
    navigate('/');
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && newExp.trim() && newPrice) {
      handleAdd();
    }
  };

  // Guard route: redirect unauthenticated users to the login page
  if (!isAuth) {
    return <Navigate to="/" />;
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-900 via-purple-900 to-slate-900 p-4 md:p-8">
      {/* Animated background blobs */}
      <div className="absolute inset-0 overflow-hidden pointer-events-none">
        <div className="absolute top-0 left-1/4 w-96 h-96 bg-purple-500 rounded-full mix-blend-multiply filter blur-3xl opacity-10 animate-blob"></div>
        <div className="absolute top-1/2 right-1/4 w-96 h-96 bg-blue-500 rounded-full mix-blend-multiply filter blur-3xl opacity-10 animate-blob animation-delay-2s"></div>
        <div className="absolute -bottom-32 left-1/2 w-96 h-96 bg-pink-500 rounded-full mix-blend-multiply filter blur-3xl opacity-10 animate-blob animation-delay-4s"></div>
      </div>

      <div className="relative z-10">
        {/* Navigation bar */}
        <nav className="flex flex-col sm:flex-row sm:justify-between sm:items-center mb-12 space-y-4 sm:space-y-0 pb-8 border-b border-purple-500/30">
          <div className="flex items-center space-x-3">
            <span className="text-4xl">💰</span>
            <h1 className="text-4xl font-bold bg-gradient-to-r from-blue-400 via-purple-400 to-pink-400 bg-clip-text text-transparent">
              Budget Buddy
            </h1>
          </div>
          <div className="flex items-center space-x-6">
            <div className="flex items-center space-x-3">
              <div className="w-12 h-12 rounded-full bg-gradient-to-br from-purple-400 to-pink-400 flex items-center justify-center text-white font-bold text-lg shadow-lg">
                {name.charAt(0).toUpperCase()}
              </div>
              <div>
                <p className="font-semibold text-white">Welcome back,</p>
                <p className="text-purple-300 text-sm">{name}</p>
              </div>
            </div>
            <button
              onClick={handleSignOut}
              className="bg-gradient-to-r from-red-500 to-pink-500 hover:from-red-600 hover:to-pink-600 text-white px-6 py-2 rounded-lg transition-all duration-300 transform hover:scale-105 shadow-lg font-semibold"
            >
              Sign Out
            </button>
          </div>
        </nav>

        {/* Overview Cards */}
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-6 mb-8">
          {/* Balance Card */}
          <div className="group relative">
            <div className="absolute inset-0 bg-gradient-to-r from-green-500 to-emerald-500 rounded-2xl blur opacity-75 group-hover:opacity-100 transition duration-500 transform group-hover:scale-105"></div>
            <div className="relative bg-slate-800 rounded-2xl p-8 backdrop-blur-xl border border-green-500/30 hover:border-green-500/60 transition-all duration-300 transform hover:scale-105">
              <div className="flex items-center justify-between mb-4">
                <span className="text-3xl">⚖️</span>
                <p className="text-xs font-semibold text-gray-400 uppercase tracking-wider">Balance</p>
              </div>
              <p
                className={`text-4xl font-bold ${
                  total.balance >= 0 ? 'text-green-400' : 'text-red-400'
                }`}
              >
                ₹{Math.abs(total.balance).toLocaleString()}
              </p>
              <p className="text-xs text-gray-400 mt-2">
                {total.balance >= 0 ? '📈 Healthy' : '📉 Deficit'}
              </p>
            </div>
          </div>

          {/* Income Card */}
          <div className="group relative">
            <div className="absolute inset-0 bg-gradient-to-r from-blue-500 to-cyan-500 rounded-2xl blur opacity-75 group-hover:opacity-100 transition duration-500 transform group-hover:scale-105"></div>
            <div className="relative bg-slate-800 rounded-2xl p-8 backdrop-blur-xl border border-blue-500/30 hover:border-blue-500/60 transition-all duration-300 transform hover:scale-105">
              <div className="flex items-center justify-between mb-4">
                <span className="text-3xl">📈</span>
                <p className="text-xs font-semibold text-gray-400 uppercase tracking-wider">Income</p>
              </div>
              <p className="text-4xl font-bold text-blue-400">
                ₹{total.income.toLocaleString()}
              </p>
              <p className="text-xs text-gray-400 mt-2">
                {transactions.filter(t => t.type === 'Income').length} transactions
              </p>
            </div>
          </div>

          {/* Expense Card */}
          <div className="group relative">
            <div className="absolute inset-0 bg-gradient-to-r from-red-500 to-orange-500 rounded-2xl blur opacity-75 group-hover:opacity-100 transition duration-500 transform group-hover:scale-105"></div>
            <div className="relative bg-slate-800 rounded-2xl p-8 backdrop-blur-xl border border-red-500/30 hover:border-red-500/60 transition-all duration-300 transform hover:scale-105">
              <div className="flex items-center justify-between mb-4">
                <span className="text-3xl">📉</span>
                <p className="text-xs font-semibold text-gray-400 uppercase tracking-wider">Expense</p>
              </div>
              <p className="text-4xl font-bold text-red-400">
                ₹{total.expense.toLocaleString()}
              </p>
              <p className="text-xs text-gray-400 mt-2">
                {transactions.filter(t => t.type === 'Expense').length} transactions
              </p>
            </div>
          </div>
        </div>

        {/* Main content area */}
        <div className="grid lg:grid-cols-2 gap-8">
          {/* Entry form */}
          <div className="group relative">
            <div className="absolute inset-0 bg-gradient-to-r from-purple-500 to-pink-500 rounded-2xl blur opacity-50 group-hover:opacity-75 transition duration-500"></div>
            <div className="relative bg-slate-800/90 backdrop-blur-xl rounded-2xl p-8 border border-purple-500/30 hover:border-purple-500/60 transition-all duration-300">
              <h3 className="text-2xl font-bold text-transparent bg-gradient-to-r from-purple-400 to-pink-400 bg-clip-text mb-6">
                ✨ Add Transaction
              </h3>

              <div className="space-y-4">
                <div>
                  <label className="block text-sm font-semibold text-gray-300 mb-2">Description</label>
                  <input
                    type="text"
                    placeholder="e.g., Grocery shopping"
                    value={newExp}
                    onChange={(e) => setNewExp(e.target.value)}
                    onKeyPress={handleKeyPress}
                    disabled={isSubmitting}
                    className="w-full px-5 py-3 rounded-xl border-2 border-purple-500/30 focus:border-purple-500/60 focus:outline-none transition-all bg-slate-700/50 text-white placeholder-gray-500 disabled:opacity-60 disabled:cursor-not-allowed shadow-lg focus:shadow-purple-500/30"
                  />
                </div>

                <div>
                  <label className="block text-sm font-semibold text-gray-300 mb-2">Amount (₹)</label>
                  <input
                    type="number"
                    placeholder="0.00"
                    value={newPrice}
                    onChange={(e) => setNewPrice(e.target.value)}
                    onKeyPress={handleKeyPress}
                    disabled={isSubmitting}
                    className="w-full px-5 py-3 rounded-xl border-2 border-purple-500/30 focus:border-purple-500/60 focus:outline-none transition-all bg-slate-700/50 text-white placeholder-gray-500 disabled:opacity-60 disabled:cursor-not-allowed shadow-lg focus:shadow-purple-500/30"
                  />
                </div>

                <div>
                  <label className="block text-sm font-semibold text-gray-300 mb-3">Type</label>
                  <div className="flex gap-4">
                    <label className="flex-1 relative cursor-pointer group/label">
                      <input
                        type="radio"
                        name="type"
                        value="Expense"
                        checked={newType === 'Expense'}
                        onChange={(e) => setNewType(e.target.value)}
                        className="sr-only"
                      />
                      <div className={`p-3 rounded-xl text-center font-semibold transition-all duration-300 border-2 ${
                        newType === 'Expense'
                          ? 'bg-red-500/30 border-red-500/60 text-red-300'
                          : 'bg-slate-700/50 border-slate-600/50 text-gray-300 group-hover/label:border-red-500/40'
                      }`}>
                        📉 Expense
                      </div>
                    </label>
                    <label className="flex-1 relative cursor-pointer group/label">
                      <input
                        type="radio"
                        name="type"
                        value="Income"
                        checked={newType === 'Income'}
                        onChange={(e) => setNewType(e.target.value)}
                        className="sr-only"
                      />
                      <div className={`p-3 rounded-xl text-center font-semibold transition-all duration-300 border-2 ${
                        newType === 'Income'
                          ? 'bg-green-500/30 border-green-500/60 text-green-300'
                          : 'bg-slate-700/50 border-slate-600/50 text-gray-300 group-hover/label:border-green-500/40'
                      }`}>
                        📈 Income
                      </div>
                    </label>
                  </div>
                </div>

                <button
                  onClick={handleAdd}
                  disabled={isSubmitting || !newExp.trim() || !newPrice}
                  className="w-full bg-gradient-to-r from-purple-500 to-pink-500 hover:from-purple-600 hover:to-pink-600 disabled:from-gray-600 disabled:to-gray-700 text-white font-bold py-4 px-6 rounded-xl transition-all duration-300 transform hover:scale-105 active:scale-95 disabled:opacity-60 disabled:cursor-not-allowed shadow-xl hover:shadow-purple-500/50 text-lg flex items-center justify-center gap-2"
                >
                  {isSubmitting ? (
                    <>
                      <span className="animate-spin">⏳</span>
                      Adding...
                    </>
                  ) : (
                    <>
                      <span>Add Entry</span>
                      <span>✨</span>
                    </>
                  )}
                </button>
              </div>
            </div>
          </div>

          {/* Transactions list */}
          <div className="group relative">
            <div className="absolute inset-0 bg-gradient-to-r from-blue-500 to-cyan-500 rounded-2xl blur opacity-50 group-hover:opacity-75 transition duration-500"></div>
            <div className="relative bg-slate-800/90 backdrop-blur-xl rounded-2xl p-8 border border-blue-500/30 hover:border-blue-500/60 transition-all duration-300 max-h-[500px] overflow-y-auto custom-scrollbar">
              <h2 className="text-2xl font-bold text-transparent bg-gradient-to-r from-blue-400 to-cyan-400 bg-clip-text mb-6">
                📋 Transactions
              </h2>

              {transactions.length === 0 ? (
                <div className="flex flex-col items-center justify-center py-12 text-center">
                  <span className="text-5xl mb-4">📭</span>
                  <p className="text-gray-400 text-lg">No transactions yet</p>
                  <p className="text-gray-500 text-sm mt-2">Start by adding your first transaction!</p>
                </div>
              ) : (
                <div className="space-y-3">
                  {transactions.map((tran) => (
                    <div
                      key={tran.id}
                      className={`group/trans flex items-center justify-between p-4 rounded-xl backdrop-blur-sm border-2 transition-all duration-300 transform hover:scale-102 hover:shadow-lg ${
                        tran.type === 'Expense'
                          ? 'bg-red-500/10 border-red-500/30 hover:border-red-500/60 hover:bg-red-500/20'
                          : 'bg-green-500/10 border-green-500/30 hover:border-green-500/60 hover:bg-green-500/20'
                      }`}
                    >
                      <div className="flex-1">
                        <p className="font-semibold text-white group-hover/trans:text-transparent group-hover/trans:bg-gradient-to-r group-hover/trans:from-white group-hover/trans:to-gray-200 group-hover/trans:bg-clip-text transition-all">
                          {tran.exp}
                        </p>
                        <p className="text-xs text-gray-400 mt-1">
                          {new Date(tran.createdAt).toLocaleDateString('en-IN', {
                            month: 'short',
                            day: 'numeric',
                            year: 'numeric'
                          })}
                        </p>
                      </div>
                      <div className="flex items-center gap-3">
                        <span className={`text-lg font-bold ${
                          tran.type === 'Expense' ? 'text-red-400' : 'text-green-400'
                        }`}>
                          {tran.type === 'Expense' ? '−' : '+'}₹{Number(tran.price).toLocaleString()}
                        </span>
                        <button
                          onClick={() => handleDelete(tran.id)}
                          className="bg-red-500/30 hover:bg-red-500/60 text-red-300 px-3 py-1 rounded-lg transition-all duration-200 text-sm font-semibold opacity-0 group-hover/trans:opacity-100"
                        >
                          ✕
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* CSS animations */}
      <style>{`
        @keyframes blob {
          0%, 100% {
            transform: translate(0, 0) scale(1);
          }
          33% {
            transform: translate(30px, -50px) scale(1.1);
          }
          66% {
            transform: translate(-20px, 20px) scale(0.9);
          }
        }

        .animate-blob {
          animation: blob 7s infinite;
        }

        .animation-delay-2s {
          animation-delay: 2s;
        }

        .animation-delay-4s {
          animation-delay: 4s;
        }

        .custom-scrollbar::-webkit-scrollbar {
          width: 6px;
        }

        .custom-scrollbar::-webkit-scrollbar-track {
          background: rgba(100, 116, 139, 0.1);
          border-radius: 10px;
        }

        .custom-scrollbar::-webkit-scrollbar-thumb {
          background: rgba(147, 51, 234, 0.5);
          border-radius: 10px;
        }

        .custom-scrollbar::-webkit-scrollbar-thumb:hover {
          background: rgba(147, 51, 234, 0.8);
        }

        .hover\:scale-102:hover {
          transform: scale(1.02);
        }
      `}</style>
    </div>
  );
};
